public class LongestPalindrome {
    static String expand(String s, int lo, int hi){
        while(lo>=0&&hi<s.length()&&s.charAt(lo)==s.charAt(hi)){lo--;hi++;}
        return s.substring(lo+1,hi); // after loop, lo+1..hi-1 is palindrome
    }
    public static String longestPalindrome(String s){
        String res="";
        for(int i=0;i<s.length();i++){
            String odd=expand(s,i,i);     // odd-length center
            String even=expand(s,i,i+1); // even-length center
            if(odd.length()>res.length()) res=odd;
            if(even.length()>res.length()) res=even;
        }
        return res;
    }
    public static void main(String[] args){
        System.out.println(longestPalindrome("babad")); // bab or aba
        System.out.println(longestPalindrome("cbbd"));  // bb
        System.out.println(longestPalindrome("a"));     // a
        System.out.println("O(n²) time, O(1) space — expand around 2n-1 centers");
    }
}

