public class CountPalindromes {
    public static int countSubstrings(String s){
        int count=0;
        for(int i=0;i<s.length();i++){
            // Odd length:
            int lo=i, hi=i;
            while(lo>=0&&hi<s.length()&&s.charAt(lo)==s.charAt(hi)){count++;lo--;hi++;}
            // Even length:
            lo=i; hi=i+1;
            while(lo>=0&&hi<s.length()&&s.charAt(lo)==s.charAt(hi)){count++;lo--;hi++;}
        }
        return count;
    }
    public static void main(String[] args){
        System.out.println(countSubstrings("abc")); // 3
        System.out.println(countSubstrings("aaa")); // 6
        System.out.println("O(n²) time, O(1) space — count each valid expansion");
    }
}

