import java.util.*;
public class PalindromePartition {
    List<List<String>> result=new ArrayList<>();
    public static List<List<String>> partition(String s){
        PalindromePartition obj=new PalindromePartition();
        obj.backtrack(s,0,new ArrayList<>());
        return obj.result;
    }
    void backtrack(String s,int start,List<String> path){
        if(start==s.length()){result.add(new ArrayList<>(path));return;}
        for(int end=start+1;end<=s.length();end++){
            String sub=s.substring(start,end);
            if(isPalin(sub)){path.add(sub);backtrack(s,end,path);path.remove(path.size()-1);}
        }
    }
    static boolean isPalin(String s){int l=0,r=s.length()-1;while(l<r){if(s.charAt(l)!=s.charAt(r))return false;l++;r--;}return true;}
    public static void main(String[] args){
        System.out.println(partition("aab")); // [[a,a,b],[aa,b]]
        System.out.println(partition("a"));   // [[a]]
    }
}

