public class MinPalindromeCuts {
    public static int minCut(String s){
        int n=s.length();
        boolean[][] isPalin=new boolean[n][n];
        // Precompute palindromes with expand-around-center:
        for(int c=0;c<n;c++){
            for(int lo=c,hi=c;lo>=0&&hi<n&&s.charAt(lo)==s.charAt(hi);lo--,hi++) isPalin[lo][hi]=true;
            for(int lo=c,hi=c+1;lo>=0&&hi<n&&s.charAt(lo)==s.charAt(hi);lo--,hi++) isPalin[lo][hi]=true;
        }
        int[] cuts=new int[n]; // cuts[i] = min cuts for s[0..i]
        for(int i=0;i<n;i++){
            if(isPalin[0][i]){cuts[i]=0;continue;} // whole prefix is palindrome
            cuts[i]=i; // worst case: cut every char
            for(int j=1;j<=i;j++) if(isPalin[j][i]) cuts[i]=Math.min(cuts[i],cuts[j-1]+1);
        }
        return cuts[n-1];
    }
    public static void main(String[] args){
        System.out.println(minCut("aab")); // 1
        System.out.println(minCut("a"));   // 0
        System.out.println(minCut("ab"));  // 1
        System.out.println("O(n²) time — precompute palindromes + 1D DP");
    }
}

