public class LongestPalindromicSubseq {
    public static int longestPalindromeSubseq(String s){
        // LPS(s) = LCS(s, reverse(s))
        String rev=new StringBuilder(s).reverse().toString();
        int m=s.length(), n=rev.length();
        int[][] dp=new int[m+1][n+1];
        for(int i=1;i<=m;i++) for(int j=1;j<=n;j++){
            if(s.charAt(i-1)==rev.charAt(j-1)) dp[i][j]=dp[i-1][j-1]+1;
            else dp[i][j]=Math.max(dp[i-1][j],dp[i][j-1]);
        }
        return dp[m][n];
    }
    public static void main(String[] args){
        System.out.println(longestPalindromeSubseq("bbbab")); // 4
        System.out.println(longestPalindromeSubseq("cbbd"));  // 2
        System.out.println(longestPalindromeSubseq("a"));     // 1
        System.out.println("O(n²) time O(n²) space — LCS of s and reverse(s)");
    }
}

