import java.util.Arrays;
public class Manacher {
    public static int[] manacher(String s){
        // Transform: 'abc' → '#a#b#c#'
        StringBuilder t=new StringBuilder("#");
        for(char c:s.toCharArray()) t.append(c).append('#');
        int n=t.length();
        int[] p=new int[n]; // p[i] = radius of palindrome centered at i
        int center=0, right=0; // center and right boundary of rightmost palindrome
        for(int i=0;i<n;i++){
            int mirror=2*center-i; // mirror of i around center
            if(i<right) p[i]=Math.min(right-i,p[mirror]); // use mirror
            // Expand beyond known boundary:
            while(i+p[i]+1<n && i-p[i]-1>=0 && t.charAt(i+p[i]+1)==t.charAt(i-p[i]-1)) p[i]++;
            // Update rightmost palindrome:
            if(i+p[i]>right){center=i;right=i+p[i];}
        }
        return p;
    }
    public static void main(String[] args){
        int[] p=manacher("abacaba");
        System.out.println(Arrays.toString(p));
        // Find longest palindrome:
        int maxLen=0, maxCenter=0;
        for(int i=0;i<p.length;i++) if(p[i]>maxLen){maxLen=p[i];maxCenter=i;}
        // Convert back: center in transformed = maxCenter, radius = maxLen
        System.out.println("Manacher O(n) — each char examined at most twice");
    }
}

