import java.util.*;
public class PalindromePairs {
    static boolean isPalin(String s,int lo,int hi){
        while(lo<hi){if(s.charAt(lo)!=s.charAt(hi))return false;lo++;hi--;}
        return true;
    }
    public static List<List<Integer>> palindromePairs(String[] words){
        Map<String,Integer> map=new HashMap<>();
        for(int i=0;i<words.length;i++) map.put(words[i],i);
        List<List<Integer>> res=new ArrayList<>();
        for(int i=0;i<words.length;i++){
            String w=words[i];
            for(int k=0;k<=w.length();k++){
                String prefix=w.substring(0,k), suffix=w.substring(k);
                String revPre=new StringBuilder(prefix).reverse().toString();
                String revSuf=new StringBuilder(suffix).reverse().toString();
                // Case 1: suffix is palindrome + reverse(prefix) exists
                if(isPalin(suffix,0,suffix.length()-1)&&map.containsKey(revPre)&&map.get(revPre)!=i)
                    res.add(Arrays.asList(i,map.get(revPre)));
                // Case 2: prefix is palindrome + reverse(suffix) exists (avoid double counting k=0)
                if(k>0&&isPalin(prefix,0,prefix.length()-1)&&map.containsKey(revSuf)&&map.get(revSuf)!=i)
                    res.add(Arrays.asList(map.get(revSuf),i));
            }
        }
        return res;
    }
    public static void main(String[] args){
        System.out.println(palindromePairs(new String[]{"abcd","dcba","lls","s","sssll"}));
        System.out.println("O(n×k²) where k=avg word length");
    }
}

