public class MinInsertionsPalindrome {
    static int lps(String s){
        // LCS(s, reverse(s))
        String rev=new StringBuilder(s).reverse().toString();
        int m=s.length();
        int[][] dp=new int[m+1][m+1];
        for(int i=1;i<=m;i++) for(int j=1;j<=m;j++){
            if(s.charAt(i-1)==rev.charAt(j-1)) dp[i][j]=dp[i-1][j-1]+1;
            else dp[i][j]=Math.max(dp[i-1][j],dp[i][j-1]);
        }
        return dp[m][m];
    }
    public static int minInsertions(String s){
        // Min insertions = n - LPS(s)
        return s.length()-lps(s);
    }
    public static void main(String[] args){
        System.out.println(minInsertions("zzazz"));    // 0
        System.out.println(minInsertions("mbadm"));    // 2
        System.out.println(minInsertions("leetcode")); // 5
        System.out.println("Formula: minInsertions = n - LPS(s) = n - LCS(s, rev(s))");
        System.out.println("Intuition: LPS chars already form palindrome skeleton, rest need insertion");
    }
}

