public class PalindromeRearrange {
    public static boolean canPermutePalindrome(String s){
        int[] freq=new int[128];
        for(char c:s.toCharArray()) freq[c]++;
        int oddCount=0;
        for(int f:freq) if(f%2!=0) oddCount++;
        return oddCount<=1;
    }
    public static void main(String[] args){
        System.out.println(canPermutePalindrome("carrace")); // true
        System.out.println(canPermutePalindrome("code"));    // false
        System.out.println(canPermutePalindrome("aab"));     // true
        System.out.println("O(n) time, O(1) space — count odd-frequency chars");
        System.out.println("Palindrome rule: at most 1 char with odd frequency");
    }
}

