public class PalindromeSynthesis {
    static boolean isPalindrome(String s){
        int lo=0,hi=s.length()-1; while(lo<hi){if(s.charAt(lo)!=s.charAt(hi))return false;lo++;hi--;} return true;
    }
    static String expand(String s,int lo,int hi){
        while(lo>=0&&hi<s.length()&&s.charAt(lo)==s.charAt(hi)){lo--;hi++;} return s.substring(lo+1,hi);
    }
    static String longestPalinSubstring(String s){
        String res=""; for(int i=0;i<s.length();i++){String o=expand(s,i,i),e=expand(s,i,i+1);if(o.length()>res.length())res=o;if(e.length()>res.length())res=e;} return res;
    }
    static int countPalinSubstrings(String s){
        int cnt=0; for(int i=0;i<s.length();i++){int lo=i,hi=i;while(lo>=0&&hi<s.length()&&s.charAt(lo)==s.charAt(hi)){cnt++;lo--;hi++;}lo=i;hi=i+1;while(lo>=0&&hi<s.length()&&s.charAt(lo)==s.charAt(hi)){cnt++;lo--;hi++;}} return cnt;
    }
    static int longestPalinSubsequence(String s){
        String rev=new StringBuilder(s).reverse().toString(); int m=s.length();
        int[][] dp=new int[m+1][m+1];
        for(int i=1;i<=m;i++) for(int j=1;j<=m;j++) dp[i][j]=s.charAt(i-1)==rev.charAt(j-1)?dp[i-1][j-1]+1:Math.max(dp[i-1][j],dp[i][j-1]);
        return dp[m][m];
    }
    public static void main(String[] args){
        System.out.println("1. isPalindrome('racecar')="+isPalindrome("racecar"));
        System.out.println("2. longestPalinSubstring('babad')="+longestPalinSubstring("babad"));
        System.out.println("3. countPalinSubstrings('aaa')="+countPalinSubstrings("aaa"));
        System.out.println("4. longestPalinSubsequence('bbbab')="+longestPalinSubsequence("bbbab"));
        boolean allPass=isPalindrome("racecar")&&(longestPalinSubstring("babad").equals("bab")||longestPalinSubstring("babad").equals("aba"))&&countPalinSubstrings("aaa")==6&&longestPalinSubsequence("bbbab")==4;
        System.out.println("All pass: "+allPass);
    }
}
